    .rst_n                      (rst_n),
    .clk                        (clk),
    // REALIGN <------> ICache
    .ralgn2icache_o             (ralgn2pf),
    .icache2ralgn_i             (pf2ralgn),
    // IF <-----> REALIGN
    .ralgn2if_o                 (ralgn2dcmp),
    .if2ralgn_i                 (if2ralgn)
);

